selector_to_html = {"a[href=\"#id1\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5.1.1 </span>Motion Mode Switching<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">\uf0c1</a></h1><p><strong>The mode-switch and locomotion interfaces provide core capabilities for switching motion modes and controlling walking/running.</strong></p>", "a[href=\"../../example/Python.html#py-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.1 </span>Get robot mode<a class=\"headerlink\" href=\"#py-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>", "a[href=\"#id3\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Motion Mode Query Service<a class=\"headerlink\" href=\"#id3\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id6\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Safety Notes<a class=\"headerlink\" href=\"#id6\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id4\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Motion Mode Set Service<a class=\"headerlink\" href=\"#id4\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#id5\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Programming Examples<a class=\"headerlink\" href=\"#id5\" title=\"Link to this heading\">\uf0c1</a></h2><p>For detailed programming examples and code explanations, see:</p>", "a[href=\"../../example/Cpp.html#cpp-get-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.1 </span>Get Robot Mode<a class=\"headerlink\" href=\"#cpp-get-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p>Retrieve the robot\u2019s current operating mode by calling the <code class=\"docutils literal notranslate\"><span class=\"pre\">GetMcAction</span></code> service, including the description, and status information.</p><p><a class=\"reference internal\" href=\"../../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">Motion Mode Definitions</span></a></p>", "a[href=\"../../example/Cpp.html#cpp-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.2.2 </span>Set Robot Mode<a class=\"headerlink\" href=\"#cpp-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"../../example/Python.html#py-set-mc-action\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6.1.2 </span>Set robot mode<a class=\"headerlink\" href=\"#py-set-mc-action\" title=\"Link to this heading\">\uf0c1</a></h2><p><strong>This example uses the SetMcAction service.</strong> After running the node, enter the corresponding field value of the mode in the terminal, and the robot will immediately switch to the appropriate <a class=\"reference internal\" href=\"../../Interface/control_mod/modeswitch.html#tbl-mc-action\"><span class=\"std std-ref\">motion mode</span></a>.<br/>\n<strong>Before switching to the Stable Standing mode (<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>), ensure the robot is standing and its feet are already on the ground.</strong><br/>\n<strong>The motion mode switching must follow its state transition digram, other transitions would be rejected</strong><br/>\n<strong>Locomotion Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">LOCOMOTION_DEFAULT</span></code>) and Stable Standing Mode(<code class=\"docutils literal notranslate\"><span class=\"pre\">STAND_DEFAULT</span></code>) are unified and will auto switch internally, so switching manually to the nearer one is enough</strong></p>", "a[href=\"#id2\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Core Functions<a class=\"headerlink\" href=\"#id2\" title=\"Link to this heading\">\uf0c1</a></h2><p>Supports switching into the following basic motion modes:</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false, theme: 'material', duration: [300, 200], delay: [200, 100],

            });
        };
    };
    console.log("tippy tips loaded!");
};
